/**
 * Unit Tests for LoginPageContent Component
 *
 * Tests that the LoginPageContent component renders correctly with the new design:
 * - Full-page bg-muted background
 * - Headline h1 element
 * - Help link at bottom of page
 */
// @vitest-environment jsdom
import { describe, expect, it, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'
import { I18nProvider } from '@/ui/web/providers/I18n'
import { LoginPageContent } from '@/app/(frontend)/login/LoginPageContent'

// Mock the LoginForm component
vi.mock('@/app/(frontend)/login/LoginForm', () => ({
  LoginForm: () => <div data-testid="login-form">LoginForm</div>,
}))

// Mock next/navigation
vi.mock('next/navigation', () => ({
  useSearchParams: () => new URLSearchParams(),
}))

const mockTranslations = {
  'auth.login': {
    headline: 'Hello, ready to succeed?',
    headlineSubtitle: 'A-Guy — your personal tutor',
    needHelp: 'Need help?',
  },
}

const MockI18nProvider = ({ children }: { children: React.ReactNode }) => {
  return (
    <I18nProvider locale="en" messages={mockTranslations}>
      {children}
    </I18nProvider>
  )
}

describe('LoginPageContent', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('should render with full-page background container', () => {
    render(
      <MockI18nProvider>
        <LoginPageContent />
      </MockI18nProvider>
    )

    const container = screen.getByText('Hello, ready to succeed?').closest('div')
    expect(container).toBeTruthy()
    // Check for min-h-screen and bg-muted classes (basic check)
    const className = container?.getAttribute('class') || ''
    expect(className).toContain('min-h-screen')
    expect(className).toContain('bg-muted')
  })

  it('should render headline h1 element', () => {
    render(
      <MockI18nProvider>
        <LoginPageContent />
      </MockI18nProvider>
    )

    const headline = screen.getByRole('heading', { level: 1 })
    expect(headline).toBeTruthy()
    expect(headline.textContent).toBe('Hello, ready to succeed?')
  })

  it('should render subtitle below headline', () => {
    render(
      <MockI18nProvider>
        <LoginPageContent />
      </MockI18nProvider>
    )

    const subtitle = screen.getByText('A-Guy — your personal tutor')
    expect(subtitle).toBeTruthy()
  })

  it('should render LoginForm component', () => {
    render(
      <MockI18nProvider>
        <LoginPageContent />
      </MockI18nProvider>
    )

    expect(screen.getByTestId('login-form')).toBeTruthy()
  })

  it('should render help link at bottom of page', () => {
    render(
      <MockI18nProvider>
        <LoginPageContent />
      </MockI18nProvider>
    )

    const helpLink = screen.getByRole('link', { name: 'Need help?' })
    expect(helpLink).toBeTruthy()
    expect(helpLink.getAttribute('href')).toBe('/help')
  })
})

/**
 * Unit Tests for LoginForm Component
 *
 * Tests that the LoginForm component renders correctly with the new design:
 * - Card has max-w-md class (wider card)
 * - Card has shadow-lg class (prominent shadow)
 * - Card has rounded-xl class
 * - Decorative line element exists
 * - "Quick Entry" section label appears
 * - Signup CTA button/link exists pointing to /signup
 * - Footer text appears
 */
// @vitest-environment jsdom
import { describe, expect, it, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'
import { I18nProvider } from '@/ui/web/providers/I18n'
import { PasswordLoginProvider } from '@/ui/web/providers/PasswordLoginProvider'
import { LoginForm } from '@/app/(frontend)/login/LoginForm'

// Mock next/navigation
vi.mock('next/navigation', () => ({
  useSearchParams: () => new URLSearchParams(),
}))

// Mock the login action
vi.mock('@/app/(frontend)/login/login_authenticate-action', () => ({
  loginAction: vi.fn(),
}))

// Mock GoogleLoginButton
vi.mock('@/ui/web/auth/GoogleLoginButton', () => ({
  GoogleLoginButton: ({ returnTo }: { returnTo: string }) => (
    <button data-testid="google-login" data-return-to={returnTo}>
      Sign in with Google
    </button>
  ),
}))

const mockTranslations = {
  'auth.login': {
    quickEntry: 'Quick Entry',
    signupCTA: 'Free Registration',
    footerSecure: 'Fast and secure access.',
    footerOneClick: 'One click and you\'re in.',
    email: 'Email',
    emailPlaceholder: 'you@example.com',
    password: 'Password',
    passwordPlaceholder: 'Enter your password',
    loginButton: 'Log in',
    loggingIn: 'Logging in...',
  },
  'auth.oauth': {
    orDivider: 'or',
  },
}

const MockProviders = ({ children, passwordEnabled = false }: { children: React.ReactNode; passwordEnabled?: boolean }) => {
  return (
    <I18nProvider locale="en" messages={mockTranslations}>
      <PasswordLoginProvider value={passwordEnabled}>
        {children}
      </PasswordLoginProvider>
    </I18nProvider>
  )
}

describe('LoginForm', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('Google-only mode (passwordEnabled: false)', () => {
    it('should render card with max-w-md class', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      const card = screen.getByTestId('google-login').closest('[class*="card"]') || 
                   screen.getByTestId('google-login').closest('div')
      expect(card).toBeTruthy()
      const className = card?.getAttribute('class') || ''
      expect(className).toContain('max-w-md')
    })

    it('should render card with shadow-lg class', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      const card = screen.getByTestId('google-login').closest('div')
      expect(card).toBeTruthy()
      const className = card?.getAttribute('class') || ''
      expect(className).toContain('shadow-lg')
    })

    it('should render card with rounded-xl class', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      const card = screen.getByTestId('google-login').closest('div')
      expect(card).toBeTruthy()
      const className = card?.getAttribute('class') || ''
      expect(className).toContain('rounded-xl')
    })

    it('should render decorative line element', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      // Find the decorative line - it's a div with specific classes
      const decorativeLine = document.querySelector('div[class*="w-12"][class*="h-0.5"][class*="bg-accent"]')
      expect(decorativeLine).toBeTruthy()
    })

    it('should render Quick Entry section label', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      expect(screen.getByText('Quick Entry')).toBeTruthy()
    })

    it('should render Signup CTA button', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      const signupButton = screen.getByText('Free Registration')
      expect(signupButton).toBeTruthy()
    })

    it('should have Signup CTA link pointing to /signup', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      const signupLink = screen.getByText('Free Registration').closest('a')
      expect(signupLink).toBeTruthy()
      expect(signupLink?.getAttribute('href')).toBe('/signup')
    })

    it('should render footer secure text', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      expect(screen.getByText('Fast and secure access.')).toBeTruthy()
    })

    it('should render footer one click text', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      expect(screen.getByText("One click and you're in.")).toBeTruthy()
    })

    it('should NOT render password form when passwordEnabled is false', () => {
      render(
        <MockProviders passwordEnabled={false}>
          <LoginForm />
        </MockProviders>
      )

      expect(screen.queryByLabelText('Email')).toBeNull()
      expect(screen.queryByLabelText('Password')).toBeNull()
    })
  })

  describe('Password enabled mode (passwordEnabled: true)', () => {
    it('should render password form when passwordEnabled is true', () => {
      render(
        <MockProviders passwordEnabled={true}>
          <LoginForm />
        </MockProviders>
      )

      expect(screen.getByLabelText('Email')).toBeTruthy()
      expect(screen.getByLabelText('Password')).toBeTruthy()
    })

    it('should render Login button', () => {
      render(
        <MockProviders passwordEnabled={true}>
          <LoginForm />
        </MockProviders>
      )

      expect(screen.getByRole('button', { name: 'Log in' })).toBeTruthy()
    })
  })
})

